#!/usr/bin/env python3
"""Block `pnpm test` (vitest watch mode); steer Claude to `pnpm test:ci`."""
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if cmd.strip().startswith("pnpm test") and "test:ci" not in cmd:
        print("Use `pnpm test:ci` instead \u2014 bare `pnpm test` runs vitest in watch mode and hangs waiting for an interactive prompt (timed out at 120s). Re-run with `pnpm test:ci`.", file=sys.stderr)
        return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block Write/Edit that introduces a directly self-recursive Python function;
steer toward an iterative worklist or an explicit depth guard."""
import json, re, sys

DEF_RE = re.compile(r"^\s*def\s+(\w+)\s*\(", re.MULTILINE)

def collect_new_text(tool, inp):
    if tool == "Write":
        return inp.get("content", "")
    if tool == "Edit":
        return inp.get("new_string", "")
    if tool == "MultiEdit":
        return "\n".join(e.get("new_string", "") for e in (inp.get("edits") or []))
    return ""

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    tool = ev.get("tool_name", "")
    if tool not in ("Write", "Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    path = inp.get("file_path", "")
    if not path.endswith(".py"):
        return 0
    text = collect_new_text(tool, inp)
    if not text:
        return 0
    for m in DEF_RE.finditer(text):
        name = m.group(1)
        body = text[m.end():]
        if re.search(r"\b" + re.escape(name) + r"\s*\(", body):
            print(f"BLOCKING: `{name}` calls itself \u2014 unbounded recursion blew the stack here before (RecursionError on a 2000-node tree).", file=sys.stderr)
            print("Rewrite with an explicit worklist/iteration or add a depth guard, then retry. Do not stop. Do not ask.", file=sys.stderr)
            return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Write/Edit/MultiEdit on a .py file, run `ruff format` to normalize
indentation and quote style per project convention (fixes mixed tab/space
lint failures seen in telemetry)."""
import json, subprocess, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") not in ("Write", "Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    path = inp.get("file_path", "")
    if not path.endswith(".py"):
        return 0
    try:
        subprocess.run(["ruff", "format", path], capture_output=True, text=True, timeout=10)
    except Exception:
        pass
    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Edit/MultiEdit on an exported identifier, grep its name and old value, feed callers back to Claude."""
import json, re, subprocess, sys
EXPORT_DEF = re.compile(r"export\s+(?:default\s+)?(?:const|let|var|function|class|type|interface|enum)\s+(\w+)")
def value_of(line):
    if "=" not in line:
        return None
    rhs = line.split("=", 1)[1].strip().rstrip(";").strip()
    if len(rhs) >= 2 and rhs[0] in ("'", '"', '`') and rhs[-1] == rhs[0]:
        return rhs[1:-1]
    return None
def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") not in ("Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    edits = inp.get("edits") or [{"old_string": inp.get("old_string", ""), "new_string": inp.get("new_string", "")}]
    terms = set()
    for e in edits:
        old, new = e.get("old_string", ""), e.get("new_string", "")
        for s in (old, new):
            m = EXPORT_DEF.search(s)
            if m:
                terms.add(m.group(1))
        if EXPORT_DEF.search(old):
            v = value_of(old)
            if v:
                terms.add(v)
    if not terms:
        return 0
    out = []
    for term in sorted(terms):
        try:
            r = subprocess.run(["grep", "-rn", "--include=*.ts", "--include=*.tsx", "--include=*.js", "--include=*.jsx", "--", term, "."], capture_output=True, text=True, timeout=5)
            hits = [l for l in r.stdout.splitlines() if l][:20]
            if hits:
                out.append(f"`{term}`: {len(hits)} reference(s)")
                out.extend(f"  {h}" for h in hits)
        except Exception:
            pass
    if out:
        print("REQUIRED FOLLOW-UP: an exported identifier changed. Stale references remain:", file=sys.stderr)
        for l in out:
            print(l, file=sys.stderr)
        print("Fix each, then summarize. Do not stop. Do not ask.", file=sys.stderr)
        return 2
    return 0
if __name__ == "__main__":
    sys.exit(main())
